# ── Safe helpers ──────────────────────────────────────────────────────────────
def safe_first(lst):
    return str(lst[0]) if isinstance(lst, list) and len(lst) > 0 else ""

def safe_list(v):   return v if isinstance(v, list) else []
def safe_str(v, d=""): return str(v) if v is not None else d
def safe_float(v):
    try: return float(v)
    except: return 0.0
def safe_dict(v):   return v if isinstance(v, dict) else {}
def detect_type(fn):
    return EXT_MAP.get(("."+fn.rsplit(".",1)[-1].lower()) if "." in fn else "", "unknown")

def is_resume(r):
    txt = " ".join([safe_str(r.get("document_type")), safe_str(r.get("summary")),
                    " ".join(safe_list(r.get("key_phrases")))]).lower()
    return any(w in txt for w in ["resume","cv","curriculum","intern","skills",
                                   "education","graphic designer","bachelor"])

def extract_resume(r, raw):
    t, ents = raw.lower(), safe_dict(r.get("entities"))

    # ── SKILLS: only from curated tech list, matched in document text ──────────
    skills = set()
    for tech in RESUME_TECH:
        if tech in t:
            # Proper label
            label_map = {
                "python":"Python","sql":"SQL","llm":"LLM","nlp":"NLP",
                "aws":"AWS","git":"Git","api":"API","css":"CSS","html":"HTML",
                "bert":"BERT","lstm":"LSTM","gpt":"GPT","rag":"RAG",
                "c++":"C++","c/c++":"C/C++","r programming":"R",
                "ci/cd":"CI/CD","rest api":"REST API","mlops":"MLOps",
                "mlflow":"MLflow","fastapi":"FastAPI","opencv":"OpenCV",
                "node.js":"Node.js","scikit-learn":"Scikit-learn",
                "power bi":"Power BI","hugging face":"HuggingFace",
            }
            skills.add(label_map.get(tech, tech.title()))

    # ── SENTENCES for section extraction ──────────────────────────────────────
    sents = [s.strip() for s in raw.replace("\n", " ").split(".")
             if len(s.strip()) > 20]

    def filt(kws, n, min_len=30, max_len=280):
        return [s for s in sents
                if any(k in s.lower() for k in kws)
                and min_len < len(s) < max_len][:n]

    # ── ACHIEVEMENTS: must contain quantified or award-type language ───────────
    def filt_achievements(n):
        results = []
        for s in sents:
            sl = s.lower()
            has_kw   = any(k in sl for k in ["award","winner","finalist","rank","first","second",
                                               "hackathon","scholarship","prize","honour","honor",
                                               "selected","chosen","top","gold","silver","bronze"])
            has_num  = bool(re.search(r'\d+', s))  # has a number / metric
            has_boost= any(k in sl for k in ["boosted","increased","improved","reduced","achieved",
                                              "delivered","generated","saved","grew","scaled"])
            if (has_kw or (has_boost and has_num)) and 25 < len(s) < 280:
                results.append(s)
            if len(results) >= n:
                break
        return results

    # ── EDUCATION: must look like an actual degree / institution sentence ──────
    def filt_education(n):
        results = []
        for s in sents:
            sl = s.lower()
            has_degree = any(k in sl for k in ["b.tech","bachelor","master","m.tech","ph.d",
                                                "degree","diploma","bsc","msc","mba","be ","me ",
                                                "university","college","institute","school",
                                                "graduated","cgpa","gpa","semester"])
            if has_degree and 20 < len(s) < 280:
                results.append(s)
            if len(results) >= n:
                break
        return results

    # ── URLS ──────────────────────────────────────────────────────────────────
    urls = safe_list(ents.get("urls"))
    li = next((u for u in urls if "linkedin" in str(u).lower()), "")
    gh = next((u for u in urls if "github"   in str(u).lower()), "")
    po = next((u for u in urls if "linkedin" not in str(u).lower()
               and "github" not in str(u).lower()), "")

    # ── MISSING fields ─────────────────────────────────────────────────────────
    miss = []
    if not li:                                 miss.append("LinkedIn URL")
    if not gh:                                 miss.append("GitHub URL")
    if not safe_list(ents.get("emails")):      miss.append("Email")
    if not safe_list(ents.get("phones")):      miss.append("Phone")
    if not any(w in t for w in ["intern","experience","worked","designer","engineer",
                                 "developer","analyst","senior","junior"]):
        miss.append("Work Experience")
    if "certif" not in t:                      miss.append("Certifications")
    if not any(w in t for w in ["gpa","cgpa"]): miss.append("GPA/CGPA")

    return {
        "name":         safe_first(ents.get("names")),
        "skills":       sorted(skills),
        "emails":       safe_list(ents.get("emails")),
        "phones":       safe_list(ents.get("phones")),
        "locations":    safe_list(ents.get("locations")),
        "linkedin":     li,
        "github":       gh,
        "portfolio":    po,
        "projects":     filt(["project","built","developed","created","designed",
                               "implemented","deployed","automated"],4),
        "experience":   filt(["intern","engineer","developer","designer","senior",
                               "junior","analyst","worked","role","position"],3),
        "education":    filt_education(3),
        "achievements": filt_achievements(4),
        "missing":      miss,
    }

