def step_badge(n, label, done=False, active=False):
    if done:
        bg,tc,bc = "#d1fae5","#065f46","#6ee7b7"
        icon = "✓"
    elif active:
        bg,tc,bc = "#fef9ec","#92400e","#d4af37"
        icon = str(n)
    else:
        bg,tc,bc = "#f5f5f4","#a8a29e","#d6d3d1"
        icon = str(n)
    mono = "JetBrains Mono, monospace"
    return (f'<div style="display:flex;flex-direction:column;align-items:center;gap:4px;flex:1;">'
            f'<div style="width:32px;height:32px;border-radius:50%;background:{bg};'
            f'border:2px solid {bc};display:flex;align-items:center;justify-content:center;'
            f'font-family:{mono};font-size:11px;font-weight:700;color:{tc};">{icon}</div>'
            f'<span style="font-size:9px;color:{tc};letter-spacing:.04em;'
            f'font-family:{mono};">{label}</span>'
            f'</div>')

def steps_bar(active_idx):
    steps = ["Read","Extract","Clean","Groq AI","Entities","Sentiment","Done"]
    items = "".join(step_badge(i+1,s, done=i<active_idx, active=i==active_idx)
                    for i,s in enumerate(steps))
    # connector lines
    return (f'<div style="background:#fffef9;border:1px solid #e8d5a8;'
            f'border-radius:12px;padding:16px;box-shadow:0 2px 8px rgba(0,0,0,.04);">'
            f'<div style="display:flex;align-items:flex-start;position:relative;">'
            f'<div style="position:absolute;top:15px;left:5%;right:5%;height:2px;'
            f'background:linear-gradient(90deg,#d4af37,#f0d060,#d4af37);opacity:.3;z-index:0;"></div>'
            f'<div style="display:flex;width:100%;position:relative;z-index:1;">{items}</div>'
            f'</div></div>')


